import{gt as e,nt as t,s as n,tt as r}from"./chunks/framework.BqU7tCwc.js";var i=JSON.parse(`{"title":"Java 远程 JMX","description":"","frontmatter":{"title":"Java 远程 JMX"},"headers":[],"relativePath":"java/jvm/remote-jmx.md","filePath":"java/jvm/remote-jmx.md","lastUpdated":1784887501000}`),a={name:`java/jvm/remote-jmx.md`};function o(n,i,a,o,s,c){return e(),r(`div`,null,[...i[0]||=[t(`<h1 id="java-远程-jmx" tabindex="-1">Java 远程 JMX <a class="header-anchor" href="#java-远程-jmx" aria-label="Permalink to “Java 远程 JMX”">​</a></h1><p>本地诊断优先使用 JDK 的 Attach API 或本地 <code>jconsole</code>，不要为本地访问额外暴露远程端口。</p><h2 id="生产环境远程访问" tabindex="-1">生产环境远程访问 <a class="header-anchor" href="#生产环境远程访问" aria-label="Permalink to “生产环境远程访问”">​</a></h2><p>远程 JMX 应只在内网开放，并同时固定 RMI 端口、启用密码认证和 TLS：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-Dcom.sun.management.jmxremote.port=10053</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.rmi.port=10053</span></span>
<span class="line"><span>-Djava.rmi.server.hostname=jmx.example.internal</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.authenticate=true</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.password.file=/etc/myapp/jmxremote.password</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.access.file=/etc/myapp/jmxremote.access</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.ssl=true</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.ssl.need.client.auth=true</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.registry.ssl=true</span></span></code></pre></div><p>还需要为 JVM 和客户端分别配置可信的密钥库与信任库。密码文件包含明文密码，必须只允许运行应用的用户读写：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/myapp/jmxremote.password</span></span></code></pre></div><p><code>jmxremote.access</code> 中的监控账号应使用 <code>readonly</code>；只向受信任的运维账号授予 <code>readwrite</code>。</p><h2 id="禁止用于生产的配置" tabindex="-1">禁止用于生产的配置 <a class="header-anchor" href="#禁止用于生产的配置" aria-label="Permalink to “禁止用于生产的配置”">​</a></h2><p>不要同时设置以下两项：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-Dcom.sun.management.jmxremote.authenticate=false</span></span>
<span class="line"><span>-Dcom.sun.management.jmxremote.ssl=false</span></span></code></pre></div><p>这会使知道地址和端口的任意用户能够访问甚至控制 JVM。完整的属性说明见 <a href="https://docs.oracle.com/en/java/javase/21/management/monitoring-and-management-using-jmx-technology.html" target="_blank" rel="noreferrer">Oracle JMX 监控与管理文档</a>。</p>`,12)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};